import requests
from datetime import datetime, timedelta, timezone

PROM_URL = "https://prometheus.example.com"

def find_never_firing_alerts(days: int = 90) -> list[str]:
    '''Return alert names that have fired zero times in the last N days.'''
    end = datetime.now(timezone.utc)
    start = end - timedelta(days=days)

    # Get all alert names from config
    rules = requests.get(f"{PROM_URL}/api/v1/rules").json()
    all_alert_names = {
        r["name"]
        for g in rules["data"]["groups"]
        for r in g["rules"]
        if r["type"] == "alerting"
    }

    # Query ALERTS metric to see what has fired
    fired = requests.get(
        f"{PROM_URL}/api/v1/query_range",
        params={
            "query": "count_over_time(ALERTS{alertstate='firing'}[1h])",
            "start": start.timestamp(),
            "end": end.timestamp(),
            "step": "3600",
        },
    ).json()

    fired_names = {
        r["metric"]["alertname"]
        for r in fired["data"]["result"]
    }
    return sorted(all_alert_names - fired_names)

never_fired = find_never_firing_alerts()
print(f"Candidates for removal ({len(never_fired)} alerts):")
for name in never_fired:
    print(f"  - {name}")
